package github.leavesczy.matisse.samples.logicimport androidx.compose.runtime.Stableimport github.leavesczy.matisse.MediaResource@Stabledata class MainPageViewState(    val darkTheme: Boolean,    val gridColumns: Int,    val maxSelectable: Int,    val fastSelect: Boolean,    val singleMediaType: Boolean,    val imageEngine: MediaImageEngine,    val mediaFilterStrategy: MediaFilterStrategy,    val captureStrategy: MediaCaptureStrategy,    val useFrontCamera: Boolean,    val pickedMediaList: List<MediaResource>,    val onGridColumnsChanged: (Int) -> Unit,    val onMaxSelectableChanged: (Int) -> Unit,    val onFastSelectChanged: (Boolean) -> Unit,    val onSingleMediaTypeChanged: (Boolean) -> Unit,    val onImageEngineChanged: (MediaImageEngine) -> Unit,    val onMediaFilterStrategyChanged: (MediaFilterStrategy) -> Unit,    val onCaptureStrategyChanged: (MediaCaptureStrategy) -> Unit,    val onUseFrontCameraChanged: (Boolean) -> Unit,    val onThemeToggled: () -> Unit)@Stableenum class MediaCaptureStrategy {    Smart,    FileProvider,    MediaStore,    Disabled;}@Stableenum class MediaImageEngine {    Coil,    Glide;}@Stableenum class MediaFilterStrategy {    None,    ExcludePrevious,    PreselectPrevious;}